+    expect(code).toContain('.whereBetween("age", 18, 65)');
+    expect(code).toContain('.whereNotBetween("score", 0, 10)');
+  });
+
+  it("like/not_like filters use shorthand", () => {
+    const code = descriptorToCode(makeDesc({
+      filters: [
+        { column: "name", op: "like", value: "%alice%" },
